using System.Windows;using System.Windows.Controls;using System.Windows.Media;namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 视觉提示辅助类，用于生成和管理拖拽过程中的箭头及视觉提示元素./// </summary>internal class VisualCueHelper{    /// <summary>    /// 缓存的箭头提示控件实例.    /// </summary>    private static ContentControl? cachedArrowCue;    /// <summary>    /// Initializes a new instance of the <see cref="VisualCueHelper"/> class.    /// </summary>    public VisualCueHelper()    {        // 静态助手类通常不需要实例化.    }    /// <summary>    /// 生成一个新的箭头提示控件.    /// </summary>    /// <returns>配置好的箭头提示控件实例.</returns>    public static ContentControl GenerateArrowCue()    {        // 创建新的拖拽箭头实例.        DragArrow arrowInstance = new DragArrow();        cachedArrowCue = arrowInstance;        // 设置基础对齐属性.        arrowInstance.HorizontalAlignment = HorizontalAlignment.Left;        arrowInstance.VerticalAlignment = VerticalAlignment.Top;        arrowInstance.Height = 30.0;        // 配置变换组：缩放、旋转、平移.        TransformGroup arrowTransforms = new TransformGroup();        arrowTransforms.Children.Add(new ScaleTransform());        arrowTransforms.Children.Add(new RotateTransform());        arrowTransforms.Children.Add(new TranslateTransform());        // 应用渲染变换及其中心点.        arrowInstance.RenderTransform = arrowTransforms;        arrowInstance.Padding = new Thickness(30.0, 0.0, 30.0, 0.0);        arrowInstance.RenderTransformOrigin = new Point(0.0, 0.5);        return arrowInstance;    }    /// <summary>    /// 移除之前生成的箭头提示控件并清理缓存.    /// </summary>    internal static void RemovePreviousArrowCue()    {        // 检查缓存是否存在且是否有父级容器.        if (cachedArrowCue != null && cachedArrowCue.Parent is Panel container)        {            // 从父容器中移除该控件.            container.Children.Remove(cachedArrowCue);            // 清理静态引用.            cachedArrowCue = null;        }    }    /// <summary>    /// 根据源元素生成拖拽视觉提示对象.    /// </summary>    /// <param name="source">作为参考的源框架元素.</param>    /// <returns>新生成的视觉提示对象.</returns>    public static DragVisualCue GenerateVisualCue(FrameworkElement source)    {        // 创建视觉提示实例.        DragVisualCue visualCue = new DragVisualCue();        // 如果源元素不为空，则同步其尺寸和边距属性.        if (source != null)        {            visualCue.Width = source.ActualWidth;            visualCue.Height = source.ActualHeight;            visualCue.MinWidth = source.MinWidth;            visualCue.MaxWidth = source.MaxWidth;            visualCue.MinHeight = source.MinHeight;            visualCue.MaxHeight = source.MaxHeight;            visualCue.Margin = source.Margin;        }        return visualCue;    }}